-- ============================================================
-- Community Cricket — Seed Data
-- Run this in the Supabase SQL editor AFTER 001_initial_schema.sql
-- ============================================================
-- UUIDs here are deterministic and must match ids.ts / matchData.ts exactly.
-- Format: 00000000-0000-0000-{cat:04x}-{n:012x}
--   cat 1 = team, 2 = player, 3 = pair, 4 = match, 5 = innings

-- ============================================================
-- Fix RLS: allow scorer (local-auth, no Supabase session) to
-- insert and update deliveries without a Supabase auth session.
-- ============================================================
drop policy if exists "scorer insert deliveries" on deliveries;
drop policy if exists "scorer update deliveries" on deliveries;

create policy "scorer insert deliveries" on deliveries
  for insert with check (true);

create policy "scorer update deliveries" on deliveries
  for update using (true);

-- Enable Realtime for deliveries table (needed for live viewer)
alter publication supabase_realtime add table deliveries;

